export const KB_CHUNKS = JSON.parse(_KC);
export const KB_IDX_RAW = JSON.parse(_KI);
export const KB_N = KB_CHUNKS.length;

export function normalize(s) {
  return s.toLowerCase()
    .replace(/[Ã®Ã­]/g,'i').replace(/[Ã´Ã³]/g,'o').replace(/[Ã»Ãº]/g,'u')
    .replace(/[Ã©Ã¨ÃªÃ«]/g,'e').replace(/[Ã Ã¢Ã¤]/g,'a').replace(/[Ã¹Ã¼]/g,'u')
    .replace(/[Ã§Ã]/g,'c');
}

export function searchKB(query, topK = 4) {
  const stop = new Set(['avec','dans','pour','cette','sont','leur','leurs','nous','vous','tout','tous','toute','aussi','meme','sous','entre','vers','sans','lors','dont','sera','etre','avoir','faire','comme','plus','moins','bien','tres','selon','ainsi','notamment','peut','doit','doivent','fait','etant','ayant']);
  const words = normalize(query).match(/\b\w{4,}\b/g) || [];
  const kws = [...new Set(words.filter(w => !stop.has(w) && isNaN(w)))];
  if (!kws.length) return [];
  const scores = {};
  for (const kw of kws) {
    for (const [rawKey, packed] of Object.entries(KB_IDX_RAW)) {
      if (normalize(rawKey) === kw) {
        const idxList = packed.split(',').map(Number);
        const idf = Math.log((KB_N + 1) / (idxList.length + 1));
        for (const ci of idxList) scores[ci] = (scores[ci] || 0) + idf;
      }
    }
  }
  return Object.entries(scores)
    .sort((a,b) => b[1]-a[1]).slice(0,topK)
    .map(([i]) => KB_CHUNKS[Number(i)]);
}
